const n = Number(lines[0]);
const vals = n > 0 ? lines[1].trim().split(/\\s+/).map(Number) : [];
const k = Number(lines[2]);

// 构造链表（节点为 { val, next } 对象）
let head = null;
let tail = null;
for (const v of vals) {
  const node = { val: v, next: null };
  if (head === null) head = node;
  else tail.next = node;
  tail = node;
}

// 每 k 个一组递归翻转
const reverseKGroup = function(h, k) {
  let t = h;
  for (let i = 0; i < k; i++) {
    if (t === null) return h;
    t = t.next;
  }
  let prev = null;
  let cur = h;
  while (cur !== t) {
    const next = cur.next;
    cur.next = prev;
    prev = cur;
    cur = next;
  }
  h.next = reverseKGroup(t, k);
  return prev;
};
