      python: `import sys

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

lines = sys.stdin.read().split('\\n')
n = int(lines[0])
vals = list(map(int, lines[1].split())) if n > 0 else []
k = int(lines[2])

# 构造链表
dummy = ListNode()
cur = dummy
for v in vals:
    cur.next = ListNode(v)
    cur = cur.next

# 每 k 个一组递归翻转
def reverse_k_group(h, k):
    t = h
    for _ in range(k):
        if t is None:
            return h
        t = t.next
    prev = None
    node = h
    while node is not t:
        nxt = node.next
        node.next = prev
        prev = node
        node = nxt
    h.next = reverse_k_group(t, k)
    return prev

head = reverse_k_group(dummy.next, k)

# 输出翻转后的链表
out = []
while head is not None:
    out.append(str(head.val))
    head = head.next
print(' '.join(out))
`,
